
package Day4;

import java.util.Arrays;

public class SortingArray {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int a[] = {50,20,70,30,10,40,60};
		
		System.out.println(Arrays.toString(a));
		
		Arrays.sort(a);

		System.out.println(Arrays.toString(a));
	}

}
